import csv
from collections import defaultdict

inventory = {}
with open('inventory.csv', mode='r') as f:
    reader = csv.DictReader(f)
    for row in reader:
        pid = row[' Product_ID'].strip()
        inventory[pid] = {
            'Name': row['Name'].strip(),
            'Stock_Count': int(row['Stock_Count']),
            'Reorder_Level': int(row['Reorder_Level'])
        }

order_volumes = defaultdict(int)
ordered_pids = set()
with open('orders.csv', mode='r') as f:
    reader = csv.DictReader(f)
    for row in reader:
        pid = row['Product_ID'].strip()
        qty = int(row['Quantity'])
        order_volumes[pid] += qty
        ordered_pids.add(pid)

# 1. Products ordered that are not in the inventory system
not_in_inventory = []
for pid in ordered_pids:
    if pid not in inventory:
        not_in_inventory.append((pid, order_volumes[pid]))

# 2. Inventory items that have never been ordered
never_ordered = []
for pid, data in inventory.items():
    if pid not in ordered_pids:
        never_ordered.append((pid, data['Name']))

# 3. Products where total order volume exceeds current stock
exceeds_stock = []
for pid, volume in order_volumes.items():
    if pid in inventory:
        stock = inventory[pid]['Stock_Count']
        if volume > stock:
            exceeds_stock.append((pid, inventory[pid]['Name'], stock, volume))

print("--- Not in Inventory ---")
for pid, qty in not_in_inventory:
    print(f"{pid}: {qty}")

print("\n--- Never Ordered ---")
for pid, name in never_ordered:
    print(f"{pid}: {name}")

print("\n--- Exceeds Stock ---")
for pid, name, stock, volume in exceeds_stock:
    print(f"{pid}: {name} (Stock: {stock}, Ordered: {volume})")
